# engine/argot/research/signal/phase14/filters/autogenerated.py
"""Auto-generated file detector — comment-node match via tree-sitter, no I/O, no regex.

.. deprecated::
    Direct use of this module is deprecated.  Use
    ``argot.research.signal.phase14.adapters.PythonAdapter.is_auto_generated``
    instead.  This module is kept as a thin shim because external callers
    (validation scripts, experiments) may still import it directly.
"""

from __future__ import annotations

import tree_sitter_python as tspython
from tree_sitter import Language, Node
from tree_sitter import Parser as TsParser

_PY_LANGUAGE = Language(tspython.language())
_COMMENT_QUERY = _PY_LANGUAGE.query("(comment) @c")

# Generic "generated" anchors (case-insensitive substring match)
_GENERIC_MARKERS: tuple[str, ...] = (
    "auto generated",
    "auto-generated",
    "autogenerated",
    "auto_generated",
    "automatically generated",
    "automatically-generated",
    "automatically created",
    "machine generated",
    "machine-generated",
    "machine created",
    "programmatically generated",
    "computer generated",
    "computer-generated",
    "generated by",
    "generated file",
    "generated code",
    "generated from",
    "generated source",
    "this file was generated",
    "this file is generated",
    "this file has been generated",
    "this file is auto-generated",
    "this file is autogenerated",
    "this file was automatically",
    "this file is automatically",
    "this is a generated file",
    "this file was created by",
    "this module is generated",
    "@generated",
    "@autogenerated",
    "@auto-generated",
    "@ generated",
)

# DO NOT EDIT variants — strong machine-authorship signal when near the top of a file
_DO_NOT_EDIT_MARKERS: tuple[str, ...] = (
    "do not edit",
    "do not edit this file",
    "do not modify",
    "do not modify this file",
    "do not modify by hand",
    "do not change this file",
    "please do not edit",
    "please do not modify",
    "source of this file is",
)

# Tool-specific markers — explicit catches for known code generators
_TOOL_MARKERS: tuple[str, ...] = (
    "generated by protoc",
    "generated by the protocol buffer compiler",
    "generated by the grpc",
    "generated by grpc",
    "generated by swagger",
    "generated by openapi-generator",
    "generated by openapi",
    "generated by datamodel-code-generator",
    "generated by f2py",
    "generated by swig",
    "generated by thrift",
    "generated by capnp",
    "generated by antlr",
    "generated by sqlacodegen",
    "generated by pydantic",
    "generated by sqlalchemy",
    "generated by buf",
    "generated by betterproto",
    "generated by mypy-protobuf",
    "generated by graphql",
    "generated by graphene",
    "generated by ariadne",
    "generated by strawberry",
    "generated by ctypesgen",
    "generated by schemathesis",
    "generated by alembic",
    "generated by django",
    "generated by mako",
    "generated by jinja",
    "generated by black",
    "generated by mypyc",
    "generated by nanobind",
    "generated by pybind11",
    "created by transcrypt",
    "created by pythran",
    "rendered by templite",
    "output of",
    "produced by",
    "compiled from",
    "transpiled from",
)

_ALL_MARKERS: tuple[str, ...] = _GENERIC_MARKERS + _DO_NOT_EDIT_MARKERS + _TOOL_MARKERS

# "do not edit" / "do not modify" in the first 10 lines are sufficient on their own,
# even without a companion generated marker.
_STRONG_FIRST_10_MARKERS: tuple[str, ...] = ("do not edit", "do not modify")


def _check_comment_text(text: str, markers: tuple[str, ...]) -> bool:
    ll = text.lower()
    return any(m in ll for m in markers)


def is_auto_generated(file_source: str, head_lines: int = 40) -> bool:
    """Return True if the file header contains an auto-generation marker.

    Only comment nodes (tree-sitter ``comment`` type, i.e. lines starting
    with ``#``) are checked.  String literals and docstrings are ignored so
    that phrases like "generated by this provider" in a docstring do not
    produce false positives.

    Args:
        file_source: Full file content as a string.
        head_lines: Number of leading lines to inspect (default 40).

    Returns:
        True if any known auto-generation marker appears (case-insensitive)
        inside a comment node within the first *head_lines* lines, or if a
        strong DO-NOT-EDIT marker appears inside a comment within the first
        10 lines.  False for empty / None input.

    Falls back to a line-prefix heuristic (lines starting with ``#``) when
    tree-sitter parsing raises an exception.
    """
    if not file_source:
        return False

    try:
        parser = TsParser(_PY_LANGUAGE)
        tree = parser.parse(file_source.encode("utf-8"))
        captures: dict[str, list[Node]] = _COMMENT_QUERY.captures(tree.root_node)
        comment_nodes: list[Node] = captures.get("c", [])

        for node in comment_nodes:
            line_index = node.start_point[0]  # 0-based
            if line_index >= head_lines:
                continue
            text = node.text.decode("utf-8") if node.text else ""
            # Strong-signal check: "do not edit" / "do not modify" in first 10 lines
            if line_index < 10 and _check_comment_text(text, _STRONG_FIRST_10_MARKERS):
                return True
            # Full marker scan
            if _check_comment_text(text, _ALL_MARKERS):
                return True

        return False

    except Exception:
        # Fallback: treat lines starting with '#' as comment lines
        lines = file_source.splitlines()
        head = lines[:head_lines]

        for line in head[:10]:
            if not line.lstrip().startswith("#"):
                continue
            ll = line.lower()
            for marker in _STRONG_FIRST_10_MARKERS:
                if marker in ll:
                    return True

        for line in head:
            if not line.lstrip().startswith("#"):
                continue
            ll = line.lower()
            for marker in _ALL_MARKERS:
                if marker in ll:
                    return True

        return False
